import {
  CanActivate,
  ExecutionContext,
  ForbiddenException,
  Injectable,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import type { Role } from '@smartcart/shared-types';
import { ROLES_KEY } from '../decorators/roles.decorator';

/**
 * RBAC guard (README §2.5 A01). Reads `@Roles()` metadata and rejects (403) if
 * the JWT `role` claim is not in the allowed set. No metadata ⇒ no restriction.
 */
@Injectable()
export class RolesGuard implements CanActivate {
  constructor(private readonly reflector: Reflector) {}

  canActivate(ctx: ExecutionContext): boolean {
    const allowed = this.reflector.getAllAndOverride<Role[] | undefined>(
      ROLES_KEY,
      [ctx.getHandler(), ctx.getClass()],
    );
    if (!allowed || allowed.length === 0) return true;

    const { user } = ctx
      .switchToHttp()
      .getRequest<{ user?: { role: Role } }>();
    if (!user || !allowed.includes(user.role)) {
      throw new ForbiddenException('Insufficient role.');
    }
    return true;
  }
}
